import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class XSSSecureCode {
    public static void main(String[] args) {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        try {
            System.out.print("Enter your name: ");
            String userName = reader.readLine();

            // Sanitize user input using ESAPI
            String sanitizedUserName = ESAPI.encoder().encodeForHTML(userName);

            System.out.println("Hello, " + sanitizedUserName + "!"); // User input properly sanitized

        } catch (IOException e) {
            System.err.println("Error reading input");
        } catch (EncodingException e) {
            System.err.println("Error encoding user input");
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
